        return formatter
    }()

    private init() {
        // Private initializer for singleton
    }

    private func logMessage(level: String, category: String, message: String, details: [String: Any]? = nil, includeTimestamp: Bool = true) {
        let timestamp = includeTimestamp ? "[\(dateFormatter.string(from: Date()))]" : ""
        var logOutput = "\(timestamp) [\(level)] [\(category)]: \(message)"

        if let details = details, !details.isEmpty {
            let detailsString = details.map { key, value in
                "\(key): \(value)"
            }.joined(separator: ", ")
            logOutput += " | Details: {\(detailsString)}"
        }

        NSLog("%@", logOutput) // Use NSLog for better system integration in production
        print(logOutput)      // Use print for immediate visibility in Xcode console
    }

    // MARK: - Public Logging Functions

    func info(category: String, message: String, details: [String: Any]? = nil) {
        logMessage(level: "INFO", category: category, message: message, details: details)
    }

    func warn(category: String, message: String, details: [String: Any]? = nil) {
        logMessage(level: "WARN", category: category, message: message, details: details)
    }

    func error(category: String, message: String, error: Error? = nil, details: [String: Any]? = nil) {
        var errorDetails = details ?? [:]
        if let error = error {
            errorDetails["ErrorDescription"] = error.localizedDescription
            errorDetails["ErrorCode"] = (error as NSError).code
            errorDetails["ErrorDomain"] = (error as NSError).domain
        }
