        ]
        if let userId = userId { details["UserID"] = userId }
        if let email = email { details["Email"] = email }
        info(category: "Authentication", message: "User Logout", details: details)
    }

    func trackUserRegistration(userId: String?, email: String?, success: Bool, registrationSource: String? = nil) {
