            "Method": method
        ]
        if let payload = payload { details["RequestPayload"] = payload }
        if let headers = headers { details["RequestHeaders"] = headers }
        if let userId = userId { details["UserID"] = userId }
        if let email = email { details["Email"] = email }
        info(category: "API_Call", message: "Outgoing API Request", details: details)
    }

