        } else {
            info(category: "API_Call", message: "API Response Received (Unhandled Status)", details: details)
        }
    }

    func trackUserDataChange(userId: String?, email: String?, field: String, oldValue: Any?, newValue: Any?) {
        var details: [String: Any] = [
