        ]
        if let userId = userId { details["UserID"] = userId }
        if let email = email { details["Email"] = email }
        if let oldValue = oldValue { details["OldValue"] = oldValue }
        if let newValue = newValue { details["NewValue"] = newValue }
        info(category: "UserData", message: "User Data Changed", details: details)
    }

    func trackScreenView(screenName: String, userId: String? = nil, email: String? = nil) {
        var details: [String: Any] = [
            "ScreenName": screenName
        ]
        if let userId = userId { details["UserID"] = userId }
        if let email = email { details["Email"] = email }
        info(category: "Screen_View", message: "User navigated to screen", details: details)
    }

    func trackUserAction(actionName: String, userId: String? = nil, email: String? = nil, properties: [String: Any]? = nil) {
        var details: [String: Any] = [
            "ActionName": actionName
        ]
        if let userId = userId { details["UserID"] = userId }
        if let email = email { details["Email"] = email }
        if let properties = properties { details["Properties"] = properties }
        info(category: "User_Action", message: "User performed action", details: details)
    }

    func trackErrorCondition(category: String, message: String, error: Error? = nil, userId: String? = nil, email: String? = nil, customData: [String: Any]? = nil) {
        var details = customData ?? [:]
